import { useState, useMemo } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const ago = (ts) => {
  if (!ts) return "--";
  const d = Date.now() - new Date(ts).getTime();
  if (d < 60000) return `${Math.floor(d / 1000)}s ago`;
  if (d < 3600000) return `${Math.floor(d / 60000)}m ago`;
  return `${Math.floor(d / 3600000)}h ago`;
};

const severityColor = (s) => s === "critical" ? "red" : s === "error" ? "red" : s === "warning" ? "amber" : "blue";

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function Errors() {
  const { state, toast } = useAppStore();
  const [selectedError, setSelectedError] = useState(null);
  const [acknowledged, setAcknowledged] = useState(new Set());
  const [suppressed, setSuppressed] = useState(new Set());

  /* poll system health */
  const { data: healthData, loading } = usePoll(
    async () => { const r = await http.get("/system/health"); return r.data; },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  /* poll incidents endpoint for real error/incident data */
  const { data: incidentData } = usePoll(
    async () => { const r = await http.get("/v2/incidents"); return r.data; },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  /* derive error data: prefer healthData.errors, fall back to incidents */
  const rawErrors = healthData?.errors ?? [];
  const incidents = incidentData?.open_incidents ?? [];
  const resolvedIncidents = incidentData?.recent_resolved ?? [];

  /* Convert incidents into error-shaped objects when no native errors exist */
  const errors = rawErrors.length > 0 ? rawErrors : [...incidents, ...resolvedIncidents].map(inc => ({
    type: inc.title ?? inc.id ?? "Unknown",
    count: 1,
    severity: inc.severity ?? "warning",
    source: "system",
    first: inc.created_at,
    last: inc.created_at,
    stack: inc.description ?? "No details available.",
  }));
  const hourlyData = healthData?.error_hourly ?? healthData?.errorHourly ?? [];
  const sourceData = healthData?.error_sources ?? healthData?.errorSources ?? [];

  /* derived stats */
  const totalErrors = errors.reduce((a, b) => a + (b.count || 0), 0);
  const errorRate = totalErrors > 0 ? (totalErrors / 24).toFixed(1) : "--";
  const topSource = sourceData.length > 0 ? sourceData.reduce((a, b) => (a.count || 0) > (b.count || 0) ? a : b).name : "--";
  const mtbf = totalErrors > 0 ? (24 * 60 / totalErrors).toFixed(0) : "--";

  /* recurring patterns */
  const recurring = useMemo(() =>
    errors.filter(e => e.count >= 3 && !suppressed.has(e.type)),
    [errors, suppressed]
  );

  const totalBySource = sourceData.reduce((a, b) => a + (b.count || 0), 0);

  /* visible errors (not suppressed) */
  const visibleErrors = useMemo(() =>
    errors.filter(e => !suppressed.has(e.type)),
    [errors, suppressed]
  );

  const ack = (type) => {
    setAcknowledged(prev => new Set([...prev, type]));
    toast(`${type} acknowledged`, "info");
  };
  const suppress = (type) => {
    setSuppressed(prev => new Set([...prev, type]));
    toast(`${type} suppressed for 24h`, "info");
  };

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Error Patterns</h1>
            <div className="v2-muted">Loading error data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <>
      {/* header */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Error Patterns</h1>
          <div className="v2-muted">Exception aggregation, fault tracking, and recurring pattern detection.</div>
        </div>
      </div>

      {/* top stats */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Total Errors (24h)" value={totalErrors > 0 ? totalErrors : "--"} t={totalErrors > 30 ? "red" : "amber"} sub="All sources combined" />
        <Stat label="Error Rate" value={errorRate !== "--" ? `${errorRate}/hr` : "--"} t="amber" sub="Average per hour" />
        <Stat label="Top Source" value={topSource} t="blue" sub="Most errors by origin" />
        <Stat label="MTBF" value={mtbf !== "--" ? `${mtbf} min` : "--"} t="green" sub="Mean time between faults" />
      </div>

      {/* error aggregation table */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Error Aggregation</div>
          {visibleErrors.length === 0 ? (
            <V2EmptyState title="No Errors" message="No error data available. Errors will appear here once reported by the system health API." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "180px 60px 120px 120px 80px 80px 120px" }}>
                <span>Error Type</span>
                <span>Count</span>
                <span>First Seen</span>
                <span>Last Seen</span>
                <span>Source</span>
                <span>Severity</span>
                <span>Actions</span>
              </div>
              {visibleErrors.map(e => (
                <div key={e.type} className="v2-tr" style={{
                  gridTemplateColumns: "180px 60px 120px 120px 80px 80px 120px",
                  cursor: "pointer",
                  background: selectedError === e.type ? "rgba(150,190,255,0.06)" :
                    acknowledged.has(e.type) ? "rgba(255,255,255,0.01)" : "transparent",
                  opacity: acknowledged.has(e.type) ? 0.6 : 1,
                }}
                  onClick={() => setSelectedError(e.type === selectedError ? null : e.type)}
                >
                  <span style={{ fontWeight: 600 }}>{e.type}</span>
                  <span className={`v2-mono v2-${e.count >= 5 ? "red" : "amber"}`}>{e.count}</span>
                  <span className="v2-mono v2-muted">{ago(e.first)}</span>
                  <span className="v2-mono v2-muted">{ago(e.last)}</span>
                  <span>{e.source}</span>
                  <span className={`v2-${severityColor(e.severity)}`} style={{ fontWeight: 600, textTransform: "uppercase", fontSize: 11 }}>
                    {e.severity}
                  </span>
                  <span className="v2-row" style={{ gap: 4 }}>
                    <button className="v2-btn" style={{ fontSize: 10, padding: "3px 6px" }}
                      onClick={(ev) => { ev.stopPropagation(); ack(e.type); }}>
                      Ack
                    </button>
                    <button className="v2-btn" style={{ fontSize: 10, padding: "3px 6px" }}
                      onClick={(ev) => { ev.stopPropagation(); suppress(e.type); }}>
                      Suppress
                    </button>
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* error frequency chart + error by source */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">Error Frequency (24h)</div>
          {hourlyData.length === 0 ? (
            <V2EmptyState title="No Frequency Data" message="Hourly error frequency will appear once the API provides it." />
          ) : (
            <>
              <div style={{ display: "flex", alignItems: "flex-end", gap: 4, height: 100, marginTop: 12 }}>
                {hourlyData.map((h, i) => {
                  const maxCount = Math.max(...hourlyData.map(x => x.count), 1);
                  const pct = (h.count / maxCount) * 100;
                  return (
                    <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center" }}>
                      <div style={{
                        width: "100%", height: `${pct}%`, minHeight: h.count > 0 ? 4 : 0, borderRadius: 6,
                        background: h.count > 4
                          ? "linear-gradient(180deg, rgba(255,120,120,0.8), rgba(255,120,120,0.2))"
                          : h.count > 2
                          ? "linear-gradient(180deg, rgba(255,210,120,0.7), rgba(255,210,120,0.2))"
                          : "linear-gradient(180deg, rgba(150,190,255,0.6), rgba(150,190,255,0.15))",
                      }} title={`${h.hour}: ${h.count} errors`} />
                    </div>
                  );
                })}
              </div>
              <div className="v2-row" style={{ justifyContent: "space-between", marginTop: 8 }}>
                <span className="v2-muted" style={{ fontSize: 10 }}>00:00</span>
                <span className="v2-muted" style={{ fontSize: 10 }}>12:00</span>
                <span className="v2-muted" style={{ fontSize: 10 }}>23:00</span>
              </div>
            </>
          )}
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Errors by Source</div>
          {sourceData.length === 0 ? (
            <V2EmptyState title="No Source Data" message="Error breakdown by source will appear once the API provides it." />
          ) : (
            <div style={{ marginTop: 12 }}>
              <div style={{ display: "flex", height: 24, borderRadius: 6, overflow: "hidden", background: "rgba(255,255,255,0.04)" }}>
                {sourceData.map(s => (
                  <div key={s.name} style={{
                    width: `${totalBySource > 0 ? (s.count / totalBySource) * 100 : 0}%`,
                    background: s.color || "rgba(150,190,255,0.8)",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontSize: 10, fontWeight: 600, overflow: "hidden", whiteSpace: "nowrap",
                  }} title={`${s.name}: ${s.count}`}>
                    {totalBySource > 0 && (s.count / totalBySource) * 100 > 10 ? s.name : ""}
                  </div>
                ))}
              </div>
              {/* legend with counts */}
              <div style={{ marginTop: 12 }}>
                {sourceData.map(s => (
                  <div key={s.name} style={{
                    display: "flex", justifyContent: "space-between", alignItems: "center",
                    padding: "4px 0", fontSize: 13,
                  }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <span style={{ width: 10, height: 10, borderRadius: 6, background: s.color || "rgba(150,190,255,0.8)", display: "inline-block" }} />
                      <span>{s.name}</span>
                    </div>
                    <div>
                      <span className="v2-mono">{s.count}</span>
                      <span className="v2-muted" style={{ marginLeft: 4 }}>({totalBySource > 0 ? ((s.count / totalBySource) * 100).toFixed(0) : 0}%)</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* error detail / stack trace */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Error Detail {selectedError ? `- ${selectedError}` : "(select an error above)"}</div>
          {selectedError ? (
            <div style={{
              marginTop: 8, padding: 16, borderRadius: 10,
              background: "rgba(0,0,0,0.35)", fontFamily: "monospace", fontSize: 13,
              lineHeight: 1.6, whiteSpace: "pre-wrap", color: "rgba(255,255,255,0.82)",
              border: "1px solid rgba(255,255,255,0.06)",
            }}>
              {errors.find(e => e.type === selectedError)?.stack || "No stack trace available."}
            </div>
          ) : (
            <div className="v2-muted" style={{ marginTop: 8 }}>
              Click on an error in the aggregation table above to view its stack trace.
            </div>
          )}
        </div>
      </div>

      {/* recurring patterns */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div className="v2-ct">Recurring Patterns (3+ occurrences in 24h)</div>
          {recurring.length === 0 ? (
            <div className="v2-muted">No recurring patterns detected (or all suppressed).</div>
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "180px 60px 100px 80px 1fr" }}>
                <span>Error Type</span>
                <span>Count</span>
                <span>Source</span>
                <span>Severity</span>
                <span>Pattern</span>
              </div>
              {recurring.map(e => {
                const diffMs = e.last && e.first ? new Date(e.last) - new Date(e.first) : 0;
                const hoursBetween = isNaN(diffMs) ? 0 : (diffMs / 3600000);
                const avgInterval = e.count > 1 ? (hoursBetween / (e.count - 1)).toFixed(1) : "--";
                return (
                  <div key={e.type} className="v2-tr" style={{ gridTemplateColumns: "180px 60px 100px 80px 1fr" }}>
                    <span style={{ fontWeight: 600 }}>{e.type}</span>
                    <span className="v2-mono v2-red">{e.count}</span>
                    <span>{e.source}</span>
                    <span className={`v2-${severityColor(e.severity)}`} style={{ fontSize: 11, fontWeight: 600, textTransform: "uppercase" }}>
                      {e.severity}
                    </span>
                    <span className="v2-muted">
                      Repeats every ~{avgInterval}h over {hoursBetween}h window
                    </span>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
